class Solution {
public:
    string maximumBinaryString(string binary) {
        int n = binary.size();
        int firstZeroIdx = -1, zerosCount = 0, onesAfterFirstZero = 0;
        for (int i = 0; i < n; ++i) {
            if (binary[i] == '0') {
                if (firstZeroIdx == -1) firstZeroIdx = i;
                zerosCount++;
            } else if (firstZeroIdx != -1) {
                onesAfterFirstZero++;
            }
        }
        if (zerosCount == 0) return binary;
        string result(n, '1');
        result[n - zerosCount] = '0';
        return result;
    }
};
efficiency: HIGH
time complexity: O(N)
space complexity: O(1)
energy implications: LOW
explanation: The solution iterates through the binary string once, counting zeros and tracking the index of the first zero. It then constructs the maximum binary string by placing '1's before the last '0', effectively maximizing the binary representation.
